sql:
SELECT region_id, petrol_consumption, petrol_price, electric_vehicle_adoption_rate
FROM petrol_consumption
WHERE petrol_price > 1.0;

external_knowledge:
- "higher-than-average petrol consumption" refers to regions where the petrol consumption is greater than the overall average petrol consumption across all regions;
- "petrol consumption" is the amount of petrol used in a region;
- "petrol price" is the average price of petrol in a region.

- "financial burden of petrol is heavy" refers to a petrol tax rate greater than 10%;
- "workforce is mostly employed" refers to an unemployment rate lower than 5%;
- "robust appetite for petrol" refers to an average petrol consumption greater than 1000;
- "cost of fuel is not too light on the pocket" refers to an average petrol price greater than 1.5.

- "Heavy monetary burden" refers to a petrol tax rate greater than 0.5;
- "Flow of petrol surges beyond a certain threshold" refers to average petrol consumption greater than 5000 units;
- "Product of petrol price and tax" refers to the calculation of `petrol_price * petrol_tax`.

sql:
SELECT COUNT(region_id) 
FROM region_categorizations 
WHERE region_type_id = 1 AND STRFTIME('%Y', categorization_date) = '2023';

external_knowledge:
